sql:
SELECT COUNT(*) AS usage_count
FROM lift_usage
WHERE chair = 'Sunset' AND lift_status = 'operational';

SELECT chair, vertical_meters, weather_conditions
FROM lift_usage
WHERE season = '2007-2008';

SELECT chair, COUNT(*) AS usage_count
FROM lift_usage
GROUP BY chair;

SELECT AVG(vertical_meters) AS average_vertical_ascend
FROM lift_usage
WHERE season = '2007-2008';

